// frontend/src/components/Layout.js
import React, { useState, useEffect } from 'react';
import { useLocation, Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import pic3 from '../pictures/lightmode.jpg';
import pic4 from '../pictures/darkmode.png';
import pic5 from '../pictures/gmail.png';
import pic6 from '../pictures/facebook.png';

const Layout = ({ children }) => {
  const [isDarkMode, setIsDarkMode] = useState(localStorage.getItem('theme') === 'dark');
  const { user, logout } = useAuth();
  const location = useLocation();
  const navigate = useNavigate();

  useEffect(() => {
    document.body.classList.toggle('dark-mode', isDarkMode);
    localStorage.setItem('theme', isDarkMode ? 'dark' : 'light');
  }, [isDarkMode]);

  const toggleDarkMode = () => setIsDarkMode(!isDarkMode);
  const isActive = (path) => location.pathname === path ? 'active' : '';

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  return (
    <div className={isDarkMode ? 'dark-theme-wrapper' : 'light-theme-wrapper'}>
      <header>
        <h1>&#128506; MUSEUM JOURNAL</h1>
        <div className="mode-toggle" onClick={toggleDarkMode} style={{ cursor: 'pointer' }}>
          <img src={isDarkMode ? pic4 : pic3} alt="Toggle Mode" id="mode-icon" />
        </div>
      </header>

      <nav className="horizontal-nav">
        <ul>
          <li><Link to="/home"    className={isActive('/home')}>Home</Link></li>
          <li><Link to="/about"   className={isActive('/about')}>About Us</Link></li>
          <li><Link to="/contact" className={isActive('/contact')}>Contact Us</Link></li>

          {/* Show Register/Login only when NOT logged in */}
          {!user && (
            <>
              <li><Link to="/register" className={isActive('/register')}>Register</Link></li>
              <li><Link to="/login"    className={isActive('/login')}>Login</Link></li>
            </>
          )}

          {/* Show when logged in */}
          {user && (
            <>
              <li><Link to="/create-post" className={isActive('/create-post')}>Write Post</Link></li>
              <li><Link to="/profile"     className={isActive('/profile')}>Profile</Link></li>
              {user.role === 'admin' && (
                <li><Link to="/admin" className={isActive('/admin')}>Admin</Link></li>
              )}
              <li>
                <button
                  onClick={handleLogout}
                  style={{
                    background: 'none',
                    border: 'none',
                    color: 'white',
                    fontWeight: 'bold',
                    cursor: 'pointer',
                    padding: '15px',
                    fontSize: '1rem',
                  }}
                >
                  Logout ({user.name})
                </button>
              </li>
            </>
          )}
        </ul>
      </nav>

      <main>{children}</main>

      <footer className="footer">
        <div className="footer-logos">
          <div className="footer-item">
            <img src={pic5} alt="Gmail" className="footer-logo" />
            <span>maicadoctolero@gmail.com</span>
          </div>
          <div className="footer-item">
            <img src={pic6} alt="Facebook" className="footer-logo" />
            <span>maicadoctolero@facebook.com</span>
          </div>
        </div>
        <p>© All Rights Reserved 2026</p>
      </footer>
    </div>
  );
};

export default Layout;
